import React, { useState } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom'; // 1. Import useNavigate

function ClientDashboard() {
  const [credentials, setCredentials] = useState({
    username: '',
    password: ''
  });
  const [error, setError] = useState('');
  const navigate = useNavigate(); // 2. Initialize navigate function

  const handleChange = (e) => {
    setCredentials({ ...credentials, [e.target.name]: e.target.value });
  };

  const handleLogin = async (e) => {
    e.preventDefault();
    setError('');
    try {
      // 3. Send login request to Backend
      const res = await axios.post(`http://localhost:5000/api/client-login`, credentials);
      
      if (res.status === 200) {
        // 4. Save client data in LocalStorage so the website remembers the user
        localStorage.setItem('clientUser', JSON.stringify(res.data));
        
        alert("✅ Login Successful! Redirecting to Home...");
        
        // 5. Navigate directly to the Home Page
        navigate('/'); 
      }
    } catch (err) {
      setError("❌ Invalid Username or Password. Please try again.");
    }
  };

  return (
    <div className="container py-5 mt-5">
      <div className="row justify-content-center">
        <div className="col-md-5">
          <div className="card shadow-lg border-0 p-4 rounded-4 text-center">
            <h3 className="fw-bold mb-3 text-primary">Client Login</h3>
            <p className="text-muted mb-4">Enter your credentials to access your account.</p>
            
            <form onSubmit={handleLogin}>
              <div className="mb-3 text-start">
                <label className="small fw-bold mb-1">Username</label>
                <input 
                  type="text" 
                  name="username"
                  className="form-control py-2" 
                  placeholder="Enter Username" 
                  value={credentials.username} 
                  onChange={handleChange} 
                  required 
                />
              </div>
              <div className="mb-4 text-start">
                <label className="small fw-bold mb-1">Password</label>
                <input 
                  type="password" 
                  name="password"
                  className="form-control py-2" 
                  placeholder="••••••••" 
                  value={credentials.password} 
                  onChange={handleChange} 
                  required 
                />
              </div>
              
              <button type="submit" className="btn btn-primary w-100 fw-bold py-2 shadow-sm">
                Login & Go to Home
              </button>
            </form>
            
            {error && <div className="text-danger mt-3 small">{error}</div>}
          </div>
        </div>
      </div>
    </div>
  );
}

export default ClientDashboard;
